INSERT INTO position_categories (id, positionId, name) VALUES (18, 2, 'Analitik Düşünme ve Problem Çözme');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (59, 18, '9', 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
