INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (69, 20, '19', 'Takım arkadaşlarını, ortak başarı için heveslendirir, onları motive eder. "Biz" olgusunu yaygınlaştır.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (70, 20, '20', 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.');
