INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (72, 21, '22', 'Ekibine mentorluk yapar, yapıcı geri bildirimlerde bulunur ve yönlendirir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (73, 21, '23', 'Ekibini motive eder, olumsuzluk yaratacak durumların önüne geçmek için çaba sarf eder.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (74, 21, '24', 'Ekip içindeki anlaşmazlıkları kişiselleştirmeden şirket yararını gözeterek yönetir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (75, 21, '25', 'İnsanların yeteneklerini keşfeder ve doğru şekilde değerlendirir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (76, 21, '26', 'Görevlerin yerine getirilebilmesi için gerekli olan kaynakları belirler ve organize eder.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (77, 21, '27', 'Aldığı kararların arkasındadır ve bu kararların sorumluluğunu üstlenir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (78, 21, '28', 'Zor durumlarda ve baskı altında en etkili kararı verir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (79, 21, '29', 'Çalışanların gelişimi için öğrenme ortamı yaratır. Ekibini ve kendini sürekli geliştirir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (80, 21, '30', 'Davranışları ile ekibe örnek olur. Söyledikleri ile yaptıkları tutarlıdır.');

